using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 renamed "Discriminator" → "$type".
            // Existing documents still use "Discriminator", so pin the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: EF 9 changed id format from "EntityName|key" → "key".
            // Existing documents use "Blog|<key>", so keep the old format.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdValueGenerator>();

            // Breaking change 3: EF 9 uses hierarchical partition keys (vector).
            // If your container was created with a single /id key, no code change
            // is needed beyond HasPartitionKey above; EF 9 still supports single keys.

            // Breaking change 4: Cosmos DB does not support indexes in the
            // relational sense. EF 9 now throws instead of silently ignoring.
            // Removed HasIndex(b => b.Name) — use Cosmos indexing policy instead.
        });
    }
}

